 1	import type { FC } from 'react';
 2	import { ConsoleTimestamp } from 'src/components/ConsoleTimestamp/ConsoleTimestamp';
 3	import { useForkliftTranslation } from 'src/utils/i18n';
 4	
 5	import type { K8sResourceCondition } from '@kubev2v/types';
 6	import { HelperText, HelperTextItem } from '@patternfly/react-core';
 7	import { Table, Tbody, Td, Th, Thead, Tr } from '@patternfly/react-table';
 8	
 9	/**
10	 * React Component to display a table of conditions.
11	 *
12	 * @component
13	 * @param {ConditionsSectionProps} props - Props for the Conditions component.
14	 * @param {K8sResourceCondition[]} props.conditions - Array of conditions to be displayed.
15	 * @returns {ReactElement} A table displaying the provided conditions.
16	 */
17	export const ConditionsSection: FC<ConditionsSectionProps> = ({ conditions }) => {
18	  const { t } = useForkliftTranslation();
19	
20	  if (!conditions) {
21	    return (
22	      <HelperText>
23	        <HelperTextItem>{t('Conditions not found')}</HelperTextItem>
24	      </HelperText>
25	    );
26	  }
27	
28	  const getStatusLabel = (status: string) => {
29	    switch (status) {
30	      case 'True':
31	        return t('True');
32	      case 'False':
33	        return t('False');
34	      default:
35	        return status;
36	    }
37	  };
38	
39	  return (
40	    <Table aria-label="Expandable table" variant="compact">
41	      <Thead>
42	        <Tr>
43	          <Th width={10}>{t('Type')}</Th>
44	          <Th width={10}>{t('Status')}</Th>
45	          <Th width={20}>{t('Updated')}</Th>
46	          <Th width={10}>{t('Reason')}</Th>
47	          <Th> {t('Message')}</Th>
48	        </Tr>
49	      </Thead>
50	      <Tbody>
51	        {conditions.map((condition) => (
52	          <Tr key={condition.type}>
53	            <Td>{condition.type}</Td>
54	            <Td>{getStatusLabel(condition.status)}</Td>
55	            <Td>
56	              <ConsoleTimestamp timestamp={condition.lastTransitionTime} />
57	            </Td>
58	            <Td>{condition.reason}</Td>
59	            <Td modifier="truncate">{condition?.message || '-'}</Td>
60	          </Tr>
61	        ))}
62	      </Tbody>
63	    </Table>
64	  );
65	};
66	
67	/**
68	 * Type for the props of the Conditions component.
69	 *
70	 * @typedef {Object} ConditionsProps
71	 * @property {K8sResourceCondition[]} conditions - The conditions to be displayed.
72	 */
73	type ConditionsSectionProps = {
74	  conditions: K8sResourceCondition[];
75	};

